// Normaliza os campos independente do nome de campo enviado pelo frontend
const b = $input.first().json.body || $input.first().json || {};
return [{
  json: {
    respostas_usuario: b.content || b.respostas_usuario || '',
    etp: b.etp_content || b.etp || '',
    pesquisa_precos: b.pesquisa_precos_texto || b.pesquisa_precos || 'Nenhuma pesquisa de preços fornecida.',
    matriz_risco: b.matriz_riscos || b.matriz_risco || '',
    process_id: b.process_id || 'N/A'
  }
}];

// Extrai o JSON retornado pelo A1 e organiza os blocos
function extractJSON(text) {
  if (typeof text === 'object' && text !== null) return text;
  if (typeof text !== 'string') return {};
  try {
    const md = text.match(/```json\s*([\s\S]*?)\s*```/);
    if (md) return JSON.parse(md[1]);
    const raw = text.match(/\{[\s\S]*\}/);
    if (raw) return JSON.parse(raw[0]);
  } catch(e) {}
  return {};
}

const output = $input.first().json?.output || '';
const parsed = extractJSON(output);

// Preserve the process_id from the upstream Normalizar step
const processId = $('Normalizar_Dados').first().json.process_id || 'N/A';

return [{
  json: {
    bloco1: { ...( parsed.bloco1 || {} ), numero_processo: processId },
    bloco2: parsed.bloco2 || {},
    bloco3: parsed.bloco3 || {}
  }
}];

// Consolida os textos dos 3 blocos e monta o JSON final
const items = $input.all();

const texto1 = items[0]?.json?.output || '';
const texto2 = items[1]?.json?.output || '';
const texto3 = items[2]?.json?.output || '';

// Pega os dados estruturados do bloco1 para montar o docxtemplater
const dadosBlocos = $('Extrair_e_Separar_Blocos').first().json;
const b1 = dadosBlocos.bloco1 || {};
const b2 = dadosBlocos.bloco2 || {};
const b3 = dadosBlocos.bloco3 || {};

// Texto de preview (Markdown) para o usuário ler no sistema
const frontendPreview = [
  '# TERMO DE REFERÊNCIA',
  '',
  texto1,
  '',
  '---',
  '',
  texto2,
  '',
  '---',
  '',
  texto3
].join('\n');

// Objeto exato para o docxtemplater (tags do template_tagueado_v2.docx)
const docxData = {
  numero_processo: b1.numero_processo || 'N/A',
  objeto_contratacao: b1.objeto_contratacao || 'N/A',
  atividades_incluidas: b1.atividades_incluidas || '',
  prazo_entrega: b1.prazo_entrega || 'N/A',
  prazo_vigencia: b1.prazo_vigencia || 'N/A',
  ano_pca: b1.ano_pca || String(new Date().getFullYear()),
  is_bens_comuns: b1.is_bens_comuns !== undefined ? b1.is_bens_comuns : true,
  is_bens_especiais: b1.is_bens_especiais !== undefined ? b1.is_bens_especiais : false,
  modalidade_licitacao: b1.modalidade_licitacao || 'Pregão Eletrônico',
  itens: Array.isArray(b1.itens) ? b1.itens : [],
  aceita_subcontratacao: b2.aceita_subcontratacao !== undefined ? b2.aceita_subcontratacao : false,
  percentual_subcontratacao: b2.percentual_subcontratacao || 0,
  exige_amostra: b2.exige_amostra !== undefined ? b2.exige_amostra : false,
  exige_garantia_contratual: b2.exige_garantia_contratual !== undefined ? b2.exige_garantia_contratual : false,
  percentual_garantia: b2.percentual_garantia || 5,
  prazo_garantia: b3.prazo_garantia || '12 meses',
  tem_garantia_contratual: b3.tem_garantia_contratual !== undefined ? b3.tem_garantia_contratual : false
};

return [{
  json: {
    sucesso: true,
    frontend_preview: {
      secao_requisitos: texto2,
      secao_gestao: texto3,
      secao_infracoes: '',
      secao_entregas: texto1
    },
    docxtemplater: docxData
  }
}];
